INSERT IGNORE INTO word_of_day (date, word, english_word, definition, synonyms, antonyms) VALUES
('2026-03-25', 'αγάπη', 'Love', 'The deepest form of love and affection in Greek culture, often used to describe unconditional love.', 'έρωτας, στοργή', 'μίσος'),
